{
  "experiment_plan": {
    "what_to_compare": "自然観察の反復測定データと、短期ランダム化実験データを組み合わせて比較する。具体的には、(1) 同一参加者内での閲覧valenceの変動と直後の気分変化、(2) 事前気分の高低によるその後の閲覧valence選択の差、(3) ネガティブ閲覧条件 vs 中立閲覧条件、(4) 感情ラベル介入あり vs なし、を比較する。",
    "what_to_measure": "主要測定は、各閲覧セッション直後の気分スコア（very unhappy〜very happyの連続尺度）と、閲覧したウェブページのvalence（NRC VAD lexiconに基づくネガティブ/中立/ポジティブ分類および連続スコア）。副次測定として、次時点の閲覧選択数、精神病理3次元スコア、閲覧時間、ページカテゴリ、介入遵守度を測定する。",
    "procedure": "参加者に複数時点の短いウェブ閲覧タスクを実施する。自然観察パートでは、各時点で閲覧直前の気分を記録し、その後の閲覧履歴を収集してvalenceを推定し、閲覧直後に再度気分を測定する。実験パートでは、参加者をネガティブ閲覧条件と中立閲覧条件、または感情ラベル介入あり/なしにランダム割付し、直後の気分とその後の選択行動を記録する。解析は、個人内固定効果を用いた時系列回帰、ランダム化比較、ラグ付き相互予測モデルを事前登録された順序で実施し、各仮説について独立に判定する。",
    "identification_assumptions": [
      {
        "id": "IA1",
        "description": "ランダム割付された条件では、処置群と対照群の期待値が観測・非観測共変量について等しい。",
        "if_violated": "群間差が割付以外の要因に起因し、閲覧valenceの効果推定が交絡される。"
      },
      {
        "id": "IA2",
        "description": "自然観察パートでは、時点tの閲覧valenceは時点t直前の気分と十分に時間順序づけられており、逆向きの同時決定がない。",
        "if_violated": "気分と閲覧選択が同時に決まり、気分→閲覧の推定が因果的に識別できない。"
      },
      {
        "id": "IA3",
        "description": "個人内固定効果と時点固定効果で、時間不変の個人特性および共通ショックの主要部分を除去できる。",
        "if_violated": "安定した個人差や共通時点ショックが残り、閲覧valenceと気分の関連が擬似相関になる。"
      },
      {
        "id": "IA4",
        "description": "気分尺度とvalence分類は誤差があるが、誤分類は非差別的であり、群間・時点間で系統的に偏らない。",
        "if_violated": "測定誤差が条件依存となり、効果が過小推定または過大推定される。"
      },
      {
        "id": "IA5",
        "description": "介入や閲覧条件は、主要アウトカムに対して直接効果を持つ経路が明確であり、主要な干渉要因は閲覧valenceまたは期待の変化に限定される。",
        "if_violated": "介入が別経路で気分を変え、閲覧valence経由の解釈が不可能になる。"
      },
      {
        "id": "IA6",
        "description": "反復測定における欠測は、直前の気分や閲覧valenceに条件付きで独立、または解析で十分に調整可能である。",
        "if_violated": "欠測が悪い気分やネガティブ閲覧に依存し、推定が選択バイアスを受ける。"
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
        "accept_if": "ランダム化比較または個人内固定効果モデルで、ネガティブ閲覧後の直後気分が中立閲覧後より有意に低く、効果量の95%信頼区間が0をまたがない。",
        "reject_if": "ネガティブ閲覧後の直後気分が中立閲覧後と差がなく、効果量の95%信頼区間が0をまたぐ、または方向が逆である。",
        "hold_if": "群間差はあるが事前気分調整後に不安定、または効果量が小さく信頼区間が0近傍に広く分布する。"
      },
      {
        "id": "H2",
        "accept_if": "時点t-1の低気分が時点tのネガティブ閲覧選択数を有意に増加させ、逆方向の予測よりも強い時間順序効果が確認される。",
        "reject_if": "事前気分がその後のネガティブ閲覧を予測せず、係数が0近傍または逆符号である。",
        "hold_if": "低気分と後続閲覧の関連はあるが、時間順序が不明確、または逆方向予測と区別できない。"
      },
      {
        "id": "H3",
        "accept_if": "相互ラグモデルで、(a) ネガティブ閲覧→次時点気分低下、かつ (b) 低気分→次時点ネガティブ閲覧増加、の両方が独立に有意である。",
        "reject_if": "上記2経路のうち少なくとも一方が有意でなく、双方向フィードバックが支持されない。",
        "hold_if": "両方向の推定値はあるが、片方または両方が境界的有意性で、頑健性分析で消失する。"
      },
      {
        "id": "H4",
        "accept_if": "感情ラベル介入群で、対照群よりネガティブページ選択数が減少し、同時に直後気分が改善する。",
        "reject_if": "介入群と対照群でネガティブページ選択数も気分も差がない。",
        "hold_if": "選択数または気分のどちらか一方のみが改善し、もう一方は不変である。"
      }
    ],
    "analysis_forks": [
      "Fork A: 主解析をNRC VAD lexiconによるvalence分類で行い、感度分析としてHu-Liu Opinion lexiconとDistilBERT分類を用いる。",
      "Fork B: 気分アウトカムを連続尺度のまま解析する分岐と、二値化または標準化スコアで解析する分岐を比較する。",
      "Fork C: 自然観察データでは、個人内固定効果モデルとランダム効果モデルを比較し、固定効果を主解析とする。",
      "Fork D: 時系列解析では、同時点関連を除いたラグ1モデルと、複数ラグを含むモデルを比較する。",
      "Fork E: 介入効果はITT解析を主解析とし、遵守者のみのper-protocol解析を感度分析とする。",
      "Fork F: 欠測処理として完全ケース解析と多重代入を比較し、欠測機構の頑健性を確認する。",
      "Fork G: H1とH2は独立判定とし、H1は閲覧→気分の下流効果のみ、H2は気分→閲覧の上流効果のみで評価する。",
      "Fork H: H3はH1とH2の同時成立を必要条件とする統合判定とし、どちらか一方のみ成立した場合は双方向ループを棄却する。",
      "Fork I: H4は介入による閲覧選択変化を主要判定、気分改善を副次判定とする分岐と、両者同時成立を必要とする厳格判定分岐を比較する。"
    ]
  }
}
